sql:
SELECT 
    (SELECT COUNT(*) FROM diversity WHERE score > 0.5) AS count_high_diversity,
    (SELECT COUNT(*) FROM colleges WHERE student_body_size > 15000) AS count_large_student_bodies;

SELECT score, description
FROM course_availability
WHERE college_id = 5;

SELECT college_id, AVG(rating) AS average_rating 
FROM student_reviews 
GROUP BY college_id;
